"use client";

import { useEffect, useState, Suspense } from "react";
import { useSearchParams, useRouter } from "next/navigation";

const PAID_KEY = "ai-unni-paid";
const PAID_RESULT_KEY = "ai-unni-paid-result";
const FREE_RESULT_KEY = "ai-unni-free-result-pending";
const PAID_ORDER_ID_KEY = "ai-unni-paid-order-id";    // 부모 분석 주문 ID (시뮬용)
const SIM_HISTORY_KEY = "ai-unni-sim-history";        // 시뮬 결과 히스토리

// ─── 이론 기반 진행 단계 (분석이 오래 걸려도 믿음 있게) ───
const STEPS = [
  { msg: "가트만의 긍정:부정 상호작용 비율 계산 중", detail: "The Gottman Ratio · 5:1 균형 분석", pct: 18 },
  { msg: "애착 유형(안정·불안·회피) 판별 중", detail: "Attachment Theory · Bowlby & Ainsworth", pct: 40 },
  { msg: "4가지 위험 신호 스캔 중", detail: "비난 · 방어 · 경멸 · 담쌓기", pct: 62 },
  { msg: "전환 시도(Bids for Connection) 반응 분석", detail: "관계 유지의 핵심 지표", pct: 82 },
  { msg: "맞춤 행동 전략 생성 중", detail: "네 상황에 딱 맞는 실전 멘트", pct: 94 },
];

// ─── 시뮬레이션 전용 진행 단계 ───
const SIM_STEPS = [
  { msg: "네 답장 톤·뉘앙스 파싱 중", detail: "어휘 · 감정 강도 · 거리감 분석", pct: 22 },
  { msg: "상대 애착 스타일에 답장 대입 중", detail: "Attachment-based response modeling", pct: 50 },
  { msg: "4 Horsemen 출현 위험도 계산", detail: "비난·방어·경멸·담쌓기 예측", pct: 75 },
  { msg: "상대 반응 시뮬레이션 생성", detail: "네가 쓴 말, 걔 시점으로 돌려보는 중", pct: 92 },
];

function AnalysisProgress({ steps, header, footer }: { steps: typeof STEPS; header: string; footer: string }) {
  const [i, setI] = useState(0);
  const [smoothPct, setSmoothPct] = useState(0);

  useEffect(() => {
    const iv = setInterval(() => setI(p => Math.min(p + 1, steps.length - 1)), 4500);
    return () => clearInterval(iv);
  }, [steps.length]);

  useEffect(() => {
    const t = setTimeout(() => setSmoothPct(steps[i].pct), 100);
    return () => clearTimeout(t);
  }, [i, steps]);

  return (
    <div>
      <div
        className="w-[38px] h-[38px] mx-auto mb-4 rounded-full animate-spin"
        style={{ border: "3px solid #FFD6E0", borderTopColor: "#FF6B8A" }}
      />
      <div className="text-[10px] font-bold mb-2" style={{ color: "#E8456A", letterSpacing: 1.2 }}>
        {header}
      </div>
      <div className="text-[15px] font-bold text-[#2D2B3D] mb-1 leading-[1.4]">
        {steps[i].msg}...
      </div>
      <div className="text-[11px] text-[#8E8A9D] mb-4 italic">
        {steps[i].detail}
      </div>

      <div className="w-full max-w-[260px] mx-auto">
        <div className="h-[6px] rounded-full overflow-hidden" style={{ background: "#FFE8EC" }}>
          <div
            className="h-full rounded-full"
            style={{
              width: `${smoothPct}%`,
              background: "linear-gradient(90deg, #FF8FA3, #FF6B8A, #E8456A)",
              transition: "width 3.5s cubic-bezier(.4,0,.2,1)",
            }}
          />
        </div>
        <p className="mt-1.5 text-[11px] font-bold tabular-nums" style={{ color: "#FF6B8A" }}>
          {smoothPct}%
        </p>
      </div>

      <p className="mt-4 text-[11px] text-[#A09CB0] leading-[1.5] whitespace-pre-line">
        {footer}
      </p>
    </div>
  );
}

function SuccessInner() {
  const params = useSearchParams();
  const router = useRouter();
  const type = params.get("type") === "sim" ? "sim" : "analysis";
  const [status, setStatus] = useState<"confirming" | "analyzing" | "done" | "error">(
    "confirming"
  );
  const [error, setError] = useState<string | null>(null);

  useEffect(() => {
    const paymentKey = params.get("paymentKey");
    const orderId = params.get("orderId");
    const amountStr = params.get("amount");
    const amount = amountStr ? parseInt(amountStr, 10) : NaN;

    if (!paymentKey || !orderId || !amount) {
      setStatus("error");
      setError("결제 정보가 올바르지 않아요.");
      return;
    }

    (async () => {
      try {
        setStatus("analyzing");

        // ─── 시뮬레이션 확정 ───
        if (type === "sim") {
          const res = await fetch("/api/simulation/confirm", {
            method: "POST",
            headers: { "Content-Type": "application/json" },
            body: JSON.stringify({
              paymentKey,
              sim_order_id: orderId,
              amount,
            }),
          });
          const json = await res.json();
          if (!res.ok) {
            throw new Error(json?.error || json?.debug || "시뮬 확정 실패");
          }

          // 시뮬 히스토리에 append
          try {
            const raw = localStorage.getItem(SIM_HISTORY_KEY);
            const arr = raw ? JSON.parse(raw) : [];
            arr.unshift({
              sim_order_id: json.sim_order_id,
              draft_reply: json.draft_reply,
              result: json.result,
              created_at: new Date().toISOString(),
            });
            // 최대 20건만 유지 (로컬 용량 관리)
            localStorage.setItem(SIM_HISTORY_KEY, JSON.stringify(arr.slice(0, 20)));
          } catch {}

          setStatus("done");
          setTimeout(() => router.replace("/"), 1200);
          return;
        }

        // ─── 기존 심층분석 확정 ───
        const res = await fetch("/api/payment/confirm", {
          method: "POST",
          headers: { "Content-Type": "application/json" },
          body: JSON.stringify({ paymentKey, orderId, amount }),
        });
        const json = await res.json();
        if (!res.ok) {
          throw new Error(json?.error || json?.debug || "결제 확정 실패");
        }

        // ─── 결제 전 무료 결과가 있으면 merge (score/summary/axes/diagnosis 유지) ───
        let finalResult = json.result;
        try {
          const raw = localStorage.getItem(FREE_RESULT_KEY);
          if (raw) {
            const free = JSON.parse(raw);
            finalResult = {
              ...json.result,
              // 무료 단계에서 사용자가 이미 본 값들은 그대로 유지
              score: free.score ?? json.result.score,
              temperature: free.temperature ?? json.result.temperature,
              stage: free.stage ?? json.result.stage,
              summary: free.summary ?? json.result.summary,
              axes: free.axes ?? json.result.axes,
              diagnosis: free.diagnosis ?? json.result.diagnosis,
            };
            localStorage.removeItem(FREE_RESULT_KEY);
          }
        } catch {}

        // 유료 상태 + merge된 결과 + 시뮬용 parent orderId 저장
        try {
          localStorage.setItem(PAID_KEY, "true");
          localStorage.setItem(PAID_RESULT_KEY, JSON.stringify(finalResult));
          localStorage.setItem(PAID_ORDER_ID_KEY, orderId);
        } catch {}

        setStatus("done");
        setTimeout(() => router.replace("/"), 1200);
      } catch (e: any) {
        console.error(e);
        setStatus("error");
        setError(e?.message || String(e));
      }
    })();
  }, [params, router, type]);

  return (
    <div style={{ background: "#FFF5F7", minHeight: "100vh" }}>
      <div className="max-w-[420px] mx-auto px-4 py-10 text-center">
        <div className="bg-white rounded-[24px] p-8 border border-[#FFD6E0]">
          {status === "confirming" && (
            <>
              <div
                className="w-[36px] h-[36px] mx-auto mb-3 rounded-full animate-spin"
                style={{ border: "3px solid #FFD6E0", borderTopColor: "#FF6B8A" }}
              />
              <div className="text-[15px] font-bold text-[#2D2B3D]">결제 확인 중...</div>
            </>
          )}
          {status === "analyzing" && (
            type === "sim" ? (
              <AnalysisProgress
                steps={SIM_STEPS}
                header="💬 AI언니 답장 시뮬레이션"
                footer={"가트만 이론·애착 스타일 기반\n20초 정도 걸려요"}
              />
            ) : (
              <AnalysisProgress
                steps={STEPS}
                header="🔬 AI언니 심층 분석 중"
                footer={"가트만 관계심리학 + 애착이론 기반\n30초 정도 걸려요"}
              />
            )
          )}
          {status === "done" && (
            <>
              <div className="text-[40px] mb-2">{type === "sim" ? "💬" : "💖"}</div>
              <div className="text-[15px] font-bold text-[#2D2B3D] mb-1">
                {type === "sim" ? "시뮬 완료!" : "분석 완료!"}
              </div>
              <div className="text-[12px] text-[#8E8A9D]">잠시 후 결과 화면으로 이동해요</div>
            </>
          )}
          {status === "error" && (
            <>
              <div className="text-[40px] mb-2">😥</div>
              <div className="text-[15px] font-bold text-[#2D2B3D] mb-2">
                문제가 생겼어요
              </div>
              <div className="text-[12px] text-[#8E8A9D] mb-4 whitespace-pre-wrap">
                {error}
              </div>
              <button
                onClick={() => router.push("/")}
                className="px-5 py-2.5 rounded-full text-white text-[13px] font-bold"
                style={{
                  background: "linear-gradient(135deg, #FF6B8A, #E8456A)",
                  border: "none",
                  cursor: "pointer",
                }}>
                홈으로
              </button>
            </>
          )}
        </div>
      </div>
    </div>
  );
}

export default function PaymentSuccessPage() {
  return (
    <Suspense fallback={<div style={{ padding: 40, textAlign: "center" }}>로딩...</div>}>
      <SuccessInner />
    </Suspense>
  );
}
